#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
int n,m,t[4*N],tag[4*N];
void modify(int cur,int l,int r,int x,int y){
	if(x<=l && r<=y){
		tag[cur]^=1,t[cur]=r-l+1-t[cur];
		return;
	}
	int mid=l+r>>1;
	if(tag[cur]){
		tag[cur*2]^=1,tag[cur*2+1]^=1;
		t[cur*2]=mid-l+1-t[cur*2],t[cur*2+1]=r-mid-t[cur*2+1];
		tag[cur]=0;
	}
	if(x<=mid)
		modify(cur*2,l,mid,x,y);
	if(y>mid)
		modify(cur*2+1,mid+1,r,x,y);
	t[cur]=t[cur*2]+t[cur*2+1];
}
int query(int cur,int l,int r,int x,int y){
	if(x<=l && r<=y)
		return t[cur];
	int mid=l+r>>1,ans=0;
	if(tag[cur]){
		tag[cur*2]^=1,tag[cur*2+1]^=1;
		t[cur*2]=mid-l+1-t[cur*2],t[cur*2+1]=r-mid-t[cur*2+1];
		tag[cur]=0;
	}
	if(x<=mid)
		ans+=query(cur*2,l,mid,x,y);
	if(y>mid)
		ans+=query(cur*2+1,mid+1,r,x,y);
	return ans;
}
int main(){
	scanf("%d%d",&n,&m);
	while(m--){
		int tp,x,y;
		scanf("%d%d%d",&tp,&x,&y);
		if(!tp)
			modify(1,1,n,x,y);
		else
			printf("%d\n",query(1,1,n,x,y));
	}
	return 0;
}
